-- Fix package_results.user_id to reference profiles for schema consistency
-- All other patient-scoped tables use profiles(id), not auth.users(id)
--
-- The implicit constraint name generated by PostgreSQL for the inline FK
-- on package_results.user_id (defined in 20260620100000_create_packages_tables.sql)
-- is the default: package_results_user_id_fkey.
--
-- profiles.id IS auth.users.id (Supabase guarantees this), so no data migration
-- is needed — only the FK target changes.

ALTER TABLE public.package_results
  DROP CONSTRAINT IF EXISTS package_results_user_id_fkey;

ALTER TABLE public.package_results
  ADD CONSTRAINT package_results_user_id_fkey
    FOREIGN KEY (user_id)
    REFERENCES public.profiles(id)
    ON DELETE CASCADE;
